// Only continue if processingStatus = PENDING.
const items = $input.all();
const pending = items.filter(i => (i.json?.processingStatus ?? '').toString().trim() === 'PENDING');
return pending.length ? pending : [];

// Merge each submission (from Only PENDING) with its CleaningJobs row (Get Booking), by position.
const pendingItems = $('Only PENDING').all();
const jobItems = $input.all();
return jobItems.map((jobItem, i) => {
  const submission = pendingItems[i]?.json || {};
  const job = jobItem.json || {};
  return { json: { ...submission, ...job } };
});

// Run all pre-GPS validations: cleaner match, clock-in status, duration min/max.
const items = $input.all();
return items.map(item => {
  const j = item.json || {};

  // 1. Cleaner match
  const cleanerFromForm = (j.cleanerIdFromForm ?? '').toString().trim();
  const assignedCleaner = (j.cleanerId ?? '').toString().trim();
  if (!cleanerFromForm || !assignedCleaner || cleanerFromForm !== assignedCleaner) {
    return { json: { ...j, validationPass: 'FAIL', validationMsg: 'Cleaner not assigned to this booking' } };
  }

  // 2. Clock-in exists  job must be IN_PROGRESS
  const jobStatus = (j.status ?? '').toString().trim();
  if (jobStatus !== 'IN_PROGRESS') {
    return { json: { ...j, validationPass: 'FAIL', validationMsg: 'No approved clock-in found' } };
  }

  // 3. Duration checks
  const clockInTime = j.clockInTimeUTC ? new Date(j.clockInTimeUTC) : null;
  const checkoutTime = j.submissionTimestamp ? new Date(j.submissionTimestamp) : null;

  if (!clockInTime || isNaN(clockInTime.getTime()) || !checkoutTime || isNaN(checkoutTime.getTime())) {
    return { json: { ...j, validationPass: 'FAIL', validationMsg: 'Invalid timestamp â€” cannot calculate duration' } };
  }

  const durationMs = checkoutTime.getTime() - clockInTime.getTime();
  const durationMin = Math.round(durationMs / 60000);

  if (durationMin < 30) {
    return { json: { ...j, validationPass: 'FAIL', validationMsg: 'Checkout too soon (' + durationMin + ' min after clock-in)', durationMinutes: durationMin } };
  }

  if (durationMin > 360) {
    const durationHrs = (durationMin / 60).toFixed(1);
    return { json: { ...j, validationPass: 'FAIL', validationMsg: 'Checkout too late (' + durationHrs + ' hrs after clock-in)', durationMinutes: durationMin } };
  }

  return { json: { ...j, validationPass: 'PASS', validationMsg: 'Pre-GPS checks passed', durationMinutes: durationMin } };
});

// Combine by position: validated submission (Pass Validated Items) with coords (Get Property Coordinates).
const submissionItems = $('Pass Validated Items').all();
const coordsItems = $input.all();
const len = Math.min(submissionItems.length, coordsItems.length);
if (len === 0) return [];
const out = [];
for (let i = 0; i < len; i++) {
  const sub = submissionItems[i]?.json || {};
  const coord = coordsItems[i]?.json || {};
  out.push({ json: { ...sub, ...coord } });
}
return out;

// Haversine distance in meters between cleaner GPS and property GPS.
const items = $input.all();
const R = 6371000;
const toRad = deg => deg * (Math.PI / 180);
return items.map(item => {
  const j = item.json || {};
  const userLat = parseFloat(j.gpsLat);
  const userLng = parseFloat(j.gpsLng);
  const propertyLat = parseFloat(j.latitude);
  const propertyLng = parseFloat(j.longitude);
  let distance = NaN;
  if (Number.isFinite(userLat) && Number.isFinite(userLng) && Number.isFinite(propertyLat) && Number.isFinite(propertyLng)) {
    const dLat = toRad(propertyLat - userLat);
    const dLng = toRad(propertyLng - userLng);
    const a = Math.sin(dLat/2)*Math.sin(dLat/2) + Math.cos(toRad(userLat))*Math.cos(toRad(propertyLat))*Math.sin(dLng/2)*Math.sin(dLng/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    distance = R * c;
  }
  return { json: { ...j, distance: Number.isFinite(distance) ? Math.round(distance) : 999999 } };
});
